      competitorMapping: [
        { name: "Propacity (India)", targetCustomer: "Mid-size to Tier A residential developers in India with active CP networks.", pricing: "SaaS subscription. Approx. INR 3-8L per year depending on CP count and modules. Per-CP pricing for large networks.", discovery: "Direct sales to developer sales heads. Word of mouth in developer community. PropTech events in India.", strongestFeatures: "CP onboarding and verification workflow. Scheme management and broadcast. Mobile app for CPs. Basic lead tracking. Familiar to Indian real estate sales teams.", weakness: "Limited gamification depth. No native SAP or Salesforce integration — requires custom connectors. Redemption store and loyalty wallet absent. Analytics is basic. No GCC presence or NRI/OS brokerage handling.", marketGaps: "Gap: No gamification, no wallet, no loyalty depth. Opportunity: Win deals by demonstrating the complete CP lifecycle — onboarding to rewards — in one platform. Lead with a live demo of the redemption store.", threats: "Adding AI-driven scheme recommendation features. If they close this gap before us, their mid-market positioning strengthens." },
        { name: "Square Yards / Broker Network Platforms (India)", targetCustomer: "Developers wanting exposure to large national broker networks. IPC aggregator model.", pricing: "Lead-generation and co-brokerage commission model. Not a SaaS per-developer platform. Revenue share on bookings.", discovery: "Developer marketing teams and CEO-level direct sales. Online presence and brand recognition in broker community.", strongestFeatures: "Large registered broker base. National reach across Tier 1 cities. Online project listing visibility. Co-brokerage arrangement for leads.", weakness: "Not a CP management platform — it is a marketplace. No invoice management, no loyalty program, no collateral personalisation. Developer has no control over CP engagement or branding. Conflict of interest between own inventory and developer inventory.", marketGaps: "Gap: They are a marketplace, not a management tool. Opportunity: Position as the complement, not the competitor — developer uses us to manage CPs, then uses Square Yards for additional reach if needed.", threats: "Vertical integration risk — if Square Yards builds a full CP management layer for developer-owned CP networks, they could bundle it with their lead generation service." },
        { name: "Generic CRM-Based CP Modules (Salesforce, HubSpot custom builds)", targetCustomer: "Developers already using SFDC or HubSpot who build custom CP modules on top of the CRM.", pricing: "Custom development cost — INR 20-80L for initial build plus ongoing maintenance. Variable per developer.", discovery: "Recommendation from CRM implementation partner or IT consultancy.", strongestFeatures: "Full CRM data integration. Highly customizable to developer-specific processes. No additional vendor relationship.", weakness: "Extremely high implementation cost and time. No mobile-first CP experience out of the box. No loyalty, wallet, or gamification layer. No collateral personalisation. Requires dedicated IT maintenance. Cannot be self-served by CPs.", marketGaps: "Gap: Extremely high cost and no CP experience layer. Opportunity: Win against SFDC custom builds by showing 10x faster deployment, purpose-built CP mobile app, and pre-built SAP connector.", threats: "SFDC releasing a real-estate-specific industry cloud (Financial Services Cloud is precedent) would reduce the build cost for custom modules." },
        { name: "Sell.do (India)", targetCustomer: "Small to mid-size residential developers in India. Focused on sales CRM and lead management.", pricing: "SaaS subscription. Approx. INR 1.5-5L per year. Entry price point is competitive.", discovery: "Digital marketing. Real estate SaaS comparison platforms. Developer events and conferences.", strongestFeatures: "Affordable. Covers CP registration, lead management, and basic pipeline tracking. Designed specifically for Indian real estate.", weakness: "Limited CP loyalty and gamification features. No wallet or redemption store. SAP integration is not native. Collateral personalisation is basic. Primarily a sales CRM — CP management is secondary.", marketGaps: "Gap: No loyalty, no wallet, no gamification. Opportunity: Compete on completeness — bundle the loyalty and redemption modules into the sales pitch to show what Sell.do cannot offer today.", threats: "Aggressively adding features at low price points. If they launch a loyalty lite tier before us, mid-market developers may choose affordability over depth." },
        { name: "Loyalty and Rewards Platforms (Capillary, LoyaltyPlus — India and GCC)", targetCustomer: "Consumer-facing loyalty programs. Large enterprises in retail, FMCG, and banking. Not real estate-specific.", pricing: "Enterprise SaaS. Significant implementation cost — USD 50,000-500,000+ depending on scale. Annual license fees.", discovery: "Enterprise sales teams. Gartner and analyst reports. Industry conferences in loyalty and CX space.", strongestFeatures: "Deep loyalty engine. Sophisticated rule-based rewards. Mature redemption store with broad merchandise and experience options. Proven at large scale.", weakness: "Not designed for real estate or B2B broker management. No bookings or invoice integration. No RERA-based CP verification. No SFDC or SAP real estate-specific connectors. Requires significant customization — cost and time prohibitive for developers.", marketGaps: "Gap: Not real estate-specific — no bookings, RERA, or CP hierarchy. Opportunity: Win against loyalty platforms by demonstrating real estate-native integration depth that Capillary cannot replicate without 12 months of customization.", threats: "If a loyalty platform partners with a real estate CRM vendor and offers a pre-built connector, they could enter the market with a credible bundled offering." },
        { name: "In-House Custom CP Portals (Developer-Built)", targetCustomer: "Large Tier A developers who have invested in proprietary CP portals built by their IT teams or outsourced vendors.", pricing: "Capital expenditure build — INR 50L-2Cr+ for initial development plus ongoing IT maintenance costs.", discovery: "Not sold — built internally. Driven by IT or Digital Transformation leadership.", strongestFeatures: "Fully tailored to developer's specific processes. Deep integration with internal systems. No third-party vendor dependency.", weakness: "High total cost of ownership. Long development cycles — 12-24 months to reach parity with a commercial product. Feature updates require dedicated IT sprints. No best-practice design from market feedback. Support burden falls on internal IT.", marketGaps: "Gap: High cost, long build time, no CP experience. Opportunity: Target developers 12-18 months into a custom build who are over budget and behind schedule. Show faster time-to-value at lower total cost.", threats: "If a large developer open-sources their in-house CP portal, it could serve as a template for others and reduce the switching incentive to a commercial product." }
      ]
